  }
}

// ── Floating Item (from question blocks) ─────────────────

class FloatingItem {
  constructor(type, x, y) {
    this.type = type; // 'coin' or 'mushroom'
    this.emoji = type === 'coin' ? '🪙' : '🍄';
    this.x = x;
    this.y = y;
    this.w = TILE;
    this.h = TILE;
    this.vy = -4;
    this.alive = true;
    this.timer = 0;
  }

  update(dt) {
    this.vy += 0.3;
    this.y += this.vy;
    this.timer += dt;
    if (this.timer > 60) this.alive = false;
  }

  draw(ctx) {
    if (!this.alive) return;
    const sx = this.x - Camera.x;
    const sy = this.y - Camera.y;
    ctx.font = `${TILE - 2}px serif`;
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText(this.emoji, sx + this.w / 2, sy + this.h / 2);
  }
}

// ── Particle (score popup, effects) ──────────────────────

class Particle {
  constructor(x, y, text, color) {
    this.x = x;
    this.y = y;
    this.text = text;
    this.color = color || '#fff';
    this.vy = -1.5;
    this.life = 40;
    this.alive = true;
  }

  update(dt) {
    this.y += this.vy;
    this.life -= dt;
    if (this.life <= 0) this.alive = false;
  }

  draw(ctx) {
    if (!this.alive) return;
    const sx = this.x - Camera.x;
    const sy = this.y - Camera.y;
    ctx.globalAlpha = Math.min(1, this.life / 15);
    ctx.font = 'bold 14px Courier New';
    ctx.fillStyle = this.color;
    ctx.textAlign = 'center';
    ctx.fillText(this.text, sx, sy);
    ctx.globalAlpha = 1;
  }
}

