/* ── Reset & Layout ─────────────────────────────────────── */
*, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }

html, body {
  width: 100%; height: 100%;
  background: #000;
  display: flex;
  align-items: center;
  justify-content: center;
  overflow: hidden;
  font-family: 'Courier New', monospace;
  user-select: none;
  -webkit-user-select: none;
  touch-action: none;
}

#game-container {
  position: relative;
  width: 800px;
  height: 480px;
  border: 3px solid #333;
  border-radius: 4px;
  overflow: hidden;
  touch-action: none;
}

canvas {
  display: block;
  width: 800px;
  height: 480px;
  image-rendering: pixelated;
}

/* ── HUD ────────────────────────────────────────────────── */
#hud {
  position: absolute;
  top: 0; left: 0; right: 0;
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  padding: 10px 16px;
  pointer-events: none;
  z-index: 10;
}

#hud > div {
  color: #fff;
  font-size: 13px;
  font-weight: bold;
  text-align: center;
  text-shadow: 1px 1px 0 #000, -1px -1px 0 #000, 1px -1px 0 #000, -1px 1px 0 #000;
  line-height: 1.3;
  min-width: 60px;
}

#hud-score { text-align: left; }
#hud-lives { text-align: right; }

/* ── Overlay (Menu / Game Over / Win) ───────────────────── */
#overlay {
  position: absolute;
  inset: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  background: rgba(0,0,0,0.7);
  z-index: 20;
  color: #fff;
  text-align: center;
}

#overlay.hidden { display: none; }

#overlay-title {
  font-size: 36px;
  margin-bottom: 12px;
  text-shadow: 2px 2px 0 #000;
}

#overlay-subtitle {
  font-size: 18px;
  margin-bottom: 24px;
  color: #ccc;
}

#overlay-action {
  font-size: 16px;
  color: #ffcc00;
  animation: blink 1s step-end infinite;
}

@keyframes blink {
  50% { opacity: 0; }
}

/* ── Touch Controls (mobile only) ─────────────────────── */
#touch-controls {
  position: absolute;
  inset: 0;
  z-index: 15;
  pointer-events: none; /* let taps pass through to canvas where buttons aren't */
}

#touch-controls button {
  pointer-events: auto; /* re-enable pointer events on buttons */
  -webkit-tap-highlight-color: transparent;
  border: 2px solid rgba(255, 255, 255, 0.35);
  border-radius: 12px;
  background: rgba(255, 255, 255, 0.15);
  color: rgba(255, 255, 255, 0.85);
  font-family: inherit;
  font-weight: bold;
  outline: none;
  cursor: pointer;
}

#touch-controls button:active,
#touch-controls button.active {
  background: rgba(255, 255, 255, 0.35);
  border-color: rgba(255, 255, 255, 0.6);
}

/* D-pad (bottom-left) */
.touch-dpad {
  position: absolute;
  bottom: 16px;
  left: 16px;
  display: flex;
  gap: 8px;
}

.touch-dpad button {
  width: 64px;
  height: 64px;
  font-size: 28px;
  display: flex;
  align-items: center;
  justify-content: center;
}

/* Jump button (bottom-right) */
.touch-jump {
  position: absolute;
  bottom: 16px;
  right: 16px;
  width: 80px;
  height: 80px;
  font-size: 18px;
  border-radius: 50%;
  border-width: 3px;
}

/* Hide touch controls on desktop */
@media (min-width: 1024px) and (hover: hover) {
  #touch-controls { display: none; }
}

